-- Lateral Line Hop to Single-Leg Stick (lateral-line-hop-to-single-leg-stick)
UPDATE coaching.exercise SET
  name = 'Lateral Line Hop to Single-Leg Stick',
  description = 'Perform Lateral Line Hop to Single-Leg Stick as a low-volume, high-quality plyometric or reactive-output exposure. The exercise targets frontal-plane landing and edge control. The coach should cap volume, demand clean landings, and stop the set before contact quality fades.',
  card_summary = 'Lateral Line Hop to Single-Leg Stick is a level-3 high-impact Output drill for frontal-plane landing and edge control.',
  coach_language = 'Primary subrole: single_leg_elastic_control. Coach this as level-3 high-impact Output work: small dose, long enough rest, clean projection, quiet landings, and an immediate stop when posture, timing, alignment, or reaction quality changes.',
  athlete_language = 'Fast and clean. Leave the ground with intent, land quietly, own the finish, and reset before the next rep.',
  movement_family = 'High-Impact Level 3-4 Plyometric / Reactive Output',
  primary_phase_key = 'output',
  phase_subrole = 'single_leg_elastic_control',
  primary_order_slot = 'lateral_line_hop_single_leg_stick',
  default_sets = 2,
  default_reps = 4,
  default_work_seconds = NULL,
  default_rest_seconds = 75,
  est_seconds_per_set = 35,
  is_published = TRUE,
  visibility = 'facility',
  participant_structure = 'individual',
  movement_requirements = '{"primary_joint_actions":["ankle plantarflexion and dorsiflexion","knee flexion-extension control","hip flexion-extension","trunk bracing","acceleration step mechanics","foot strike under center of mass"],"primary_tissues":["intrinsic foot","plantar fascia","calf complex","Achilles tendon","quadriceps","patellar tendon","glutes","hip flexors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_exhale_or_relaxed_reset","balance_demand":"dynamic","coordination_demand":"high","impact_level":3,"surface_needs":"flat, non-slip, shock-absorbing surface with safe spacing","readiness_prerequisites":["Pain-free jumping, hopping, landing, and deceleration patterns.","Can demonstrate a lower-level landing or rebound progression quietly and under control.","Understands stop command and can reset between reps."]}'::jsonb,
  coaching_execution = '{"movement_description":"Perform Lateral Line Hop to Single-Leg Stick as a low-volume, high-quality plyometric or reactive-output exposure. The exercise targets frontal-plane landing and edge control. The coach should cap volume, demand clean landings, and stop the set before contact quality fades.","setup":["Choose a safe lane, surface, target, cone, hurdle, box, partner, or implement setup that matches the card.","Rehearse the lower-level pattern first and confirm the athlete can land quietly with trunk and knee-foot alignment.","Give one clear task cue and one stop cue before the set begins."],"execution_steps":["Start tall and organized with eyes up and ribs stacked over pelvis.","Create the required jump, hop, bound, drop, throw, or reactive action with high intent.","Land through the whole foot or appropriate forefoot contact without collapsing, twisting, or reaching excessively.","Stick, rebound, cut, sprint, or reset exactly as the drill requires.","Stop the set when output, timing, landing, spacing, or decision quality is no longer repeatable."],"coach_cues":["Quiet contact.","Push the ground away.","Own the landing before the next answer.","Fast intent, full reset.","Knee tracks over mid-foot."],"athlete_cues":["Quiet contact.","Push the ground away.","Own the landing before the next answer.","Fast intent, full reset.","Knee tracks over mid-foot."],"quality_gate":["Every rep looks fast, quiet, and aligned.","No visible knee collapse, trunk dumping, heel whip, toe drag, or uncontrolled rotation.","The athlete can stop, stick, or redirect on command.","The next rep is not slower or louder than the previous rep."],"common_faults":["Chasing distance or height before earning landing shape.","Adding too many contacts because the exercise looks simple.","Progressing cue complexity before the base contact is clean.","Using the drill late in the session after fatigue has dulled contact quality."],"stop_signs":["Pain, guarding, limping, or change in mechanics.","Loud or flat landings, slow ground contacts, or repeated balance losses.","Fatigue turns the drill into conditioning instead of Output quality.","Unsafe spacing, surface, equipment, or partner communication."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Acceleration, sprint, jump, or COD technical work","Lower-body strength or power support work","Sport-specific skill that benefits from fresh elastic output"],"pairs_well_after":["Dynamic warm-up","Relevant mobility/access work","Landing control or lower-level rebound prep","Movement Intelligence drill for the same direction or cue"],"good_for_sessions":["plyometric_output","jump_power","speed_agility_output","reactive_cod_output"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete has current pain, bone stress concern, tendon flare, or unresolved lower-limb injury.","Athlete cannot demonstrate a lower-level progression safely.","The surface, equipment, footwear, partner spacing, or supervision is unsafe.","The athlete is already fatigued enough that contacts are slow, loud, flat, or poorly aligned."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=ZHg88_EYQ74","https://www.youtube.com/watch?v=Jiukp-0mUIA","https://www.youtube.com/watch?v=U12iOibPX98"],"internal_notes":["Film high-impact contacts when possible.","Track total contacts and keep this out of fatigue circuits.","Verify movementRequirements.impactLevel, safety.impactLevel, and phaseProfile.impactLevel match.","Client-facing video embeds use watch?v= URLs in clinical_or_sport_science_references.","Film front and side views when possible; stop sets when contact quality fades."]}'::jsonb,
  updated_at = now()
WHERE slug = 'lateral-line-hop-to-single-leg-stick';

