  card_summary = 'Reactive Cone-Call Hop to Stick is a level-3 high-impact Output drill for visual cue response with a single controlled hop.',
  coach_language = 'Primary subrole: reactive_agility_output. Coach this as level-3 high-impact Output work: small dose, long enough rest, clean projection, quiet landings, and an immediate stop when posture, timing, alignment, or reaction quality changes.',
  athlete_language = 'Fast and clean. Leave the ground with intent, land quietly, own the finish, and reset before the next rep.',
  movement_family = 'High-Impact Level 3-4 Plyometric / Reactive Output',
  primary_phase_key = 'output',
  phase_subrole = 'reactive_agility_tumbling_output',
  primary_order_slot = 'reactive_cone_call_hop_to_stick',
  default_sets = 3,
  default_reps = 5,
  default_work_seconds = NULL,
  default_rest_seconds = 98,
  est_seconds_per_set = 35,
  is_published = TRUE,
