  movement_family = 'High-Impact Level 3-4 Plyometric / Reactive Output',
  primary_phase_key = 'output',
  phase_subrole = 'multidirectional_elastic_control',
  primary_order_slot = 'one_eighty_jump_rebound_sprint_out',
