-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'High-impact Output contacts require freshness, low volume, and clean landings before heavier strength or conditioning.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('snap-down-to-low-vertical-rebound', 'Snap-Down to Low Vertical Rebound creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because bridges a controlled snap-down into a small vertical elastic response without making the athlete chase height.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('low-box-drop-to-quarter-squat-rebound', 'Low Box Drop to Quarter-Squat Rebound creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because lets coaches expose a mild drop-to-rebound problem before taller depth or hurdle work.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('step-off-to-single-leg-stick', 'Step-Off to Single-Leg Stick creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because raises impact above low prep while still demanding a full stick before reactive progressions.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('low-hurdle-hop-to-pause-stick', 'Low Hurdle Hop to Pause Stick creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because adds a clearance constraint while the pause prevents uncontrolled continuous contacts.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('split-stance-scissor-hop-to-stick', 'Split-Stance Scissor Hop to Stick creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because teaches hip exchange and trunk control without the volume of continuous scissor jumps.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('lateral-line-hop-to-single-leg-stick', 'Lateral Line Hop to Single-Leg Stick creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because makes lateral impact coachable with a small target and a clear stick requirement.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('two-hop-vertical-rhythm-to-stick', 'Two-Hop Vertical Rhythm to Stick creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because teaches repeatability while the final stick exposes whether alignment survived the rebounds.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('pogo-pogo-stick-series', 'Pogo-Pogo-Stick Series creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because raises the common pogo into a high-impact bridge only when the final stick is owned.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('low-hurdle-lateral-hop-to-stick', 'Low Hurdle Lateral Hop to Stick creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because combines low hurdle stiffness with side-to-side landing control without continuous volume.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('drop-landing-to-45-degree-push-off', 'Drop Landing to 45-Degree Push-Off creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because builds a bridge from vertical impact to athletic redirection while keeping the angle controlled.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('broad-jump-to-backpedal-reset', 'Broad Jump to Backpedal Reset creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because keeps broad-jump power but adds a practical reset pattern that rewards balanced landing.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('skater-hop-to-forward-re-acceleration', 'Skater Hop to Forward Re-Acceleration creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because connects lateral landing control to the next athletic action instead of stopping at the stick.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('diagonal-bound-to-stick', 'Diagonal Bound to Stick creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because adds diagonal sport transfer while keeping amplitude moderate and landing accountable.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('single-leg-lateral-hop-to-stick-alt', 'Single-Leg Lateral Hop to Stick creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because valuable for high-impact unilateral tolerance without the cost of repeated rebounds.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('triple-line-hop-and-stick', 'Triple-Line Hop and Stick creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because uses limited contact count to build repeat unilateral stiffness before longer hop tests.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('carioca-bound-to-stick', 'Carioca Bound to Stick creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because turns carioca rhythm into a higher-impact elastic expression without chaotic volume.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('medial-lateral-ankle-hop-series', 'Medial-Lateral Ankle Hop Series creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because small but meaningful unilateral contacts help fill level-3 impact without requiring long jumps.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('crossover-step-to-bound-and-stick', 'Crossover Step to Bound and Stick creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because builds reorientation power while the stick keeps the athlete from over-rotating.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('hop-to-hop-to-stick-linear', 'Hop-to-Hop-to-Stick Linear creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because more demanding than one hop but still bounded by a short series and visible quality gate.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('curved-bound-to-stick', 'Curved Bound to Stick creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because adds curved force application for field and track athletes while keeping speed and volume moderate.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
  ('90-degree-jump-turn-to-stick', '90-Degree Jump Turn to Stick creates a high-quality stretch-shortening-cycle problem: the athlete must accept force, maintain alignment, and re-express force quickly enough to preserve elastic transfer. It is useful because trains rotation and landing integrity at a moderate impact level before adding rebounds.', 'Belongs in Output because impact level 3 is freshness-sensitive high-impact work. It should not be used as low-stress Prepare & Access work or as conditioning volume.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Place before heavy strength, conditioning, long sport blocks, or fatigue-based work.', 'Do not use this as a finisher, conditioning station, punishment, or warm-up filler. Do not progress height, distance, speed, cue uncertainty, and volume at the same time. Stop when contacts get loud, slow, flat, unstable, or misaligned.', 'Scale first by reducing amplitude, distance, height, contacts, approach speed, cue uncertainty, or surface demand. Progress only when every rep shows quiet contacts, stable trunk, aligned knee-foot path, and fast reset behavior.'),
